profile.postProcessScript:
			for (row in Events.Sheet[EventsOut].rows) {
				/*
				if (row.column[Date] == "12.07.2025") {
					callMacro("ex_PostProcessActions.m_HighlightRow", row, "#FF0000");
					callMacro("ex_PostProcessActions.m_HighlightRowCell", row, "Ticket", "#00FF00");
				}
				*/

				let hasOrderNumber = callMacro("ex_PostProcessActions.m_RowCellRegexIsMatch", row, "Note", "№\\s*[0-9]+");
				if (hasOrderNumber == "True") {
					callMacro("ex_PostProcessActions.m_HighlightRowCell", row, "Note", "#404040");
					callMacro("ex_PostProcessActions.m_EmphasizeRowCellTextByRegex", row, "Note", "№\\s*[0-9]+", "#FF0000", "false");
				}
			}

			if (Events.Sheet[EventsOut].count != "0") {
				callMacro("ex_PostProcessActions.m_AppendPostProcessFooterText", "EventsOut rows: {Events.Sheet[EventsOut].count}. Last date: {Events.Sheet[EventsOut].lastRow.column[Date]}");
			}

			if (Events.Sheet[EventsOut].count != "0" and Events.Sheet[EventsOut].count != "1") {
				callMacro("ex_PostProcessActions.m_AppendPostProcessFooterText", "Prev date: {Events.Sheet[EventsOut].prevRow.column[Date]}");
			}

			let dateMapKey = callMacro("ex_ResultRuntimeAdapter.m_BuildMapKey", "Events", "EventsOut", "Date");
			callMacro("ex_PostProcessActions.m_AppendPostProcessFooterText", "DSL var test. dateMapKey={dateMapKey}");
			if (dateMapKey == "Events.Sheet[EventsOut].Map[Date]") {
				callMacro("ex_PostProcessActions.m_AppendPostProcessFooterText", dateMapKey);
			}

for (row in Events.Sheet[DailyEvents].rows) {
	/* Старт блока: новая больница */
	if (row.column[Hospital] != "") {
		let txt = callMacro("ex_PostProcessActions.m_TextAppend", "", "7.2.3. З-лікування:");
		let txt = callMacro("ex_PostProcessActions.m_TextAppend", txt, "З {row.column[Hospital]}.", "\n");

		if (row.column[Rank] != "" and row.column[FIO] != "" and row.column[Position] != "") {
			let txt = callMacro("ex_PostProcessActions.m_TextAppend", txt, "{row.column[Rank]} {row.column[FIO]}, {row.column[Position]}.", "\n");
		}

		if (row.column[Vacation] != "") {
			let txt = callMacro("ex_PostProcessActions.m_TextAppend", txt, "Статус: {row.column[Vacation]}.", "\n");
		}

		if (row.column[DaysCount] != "" and row.column[DateFrom] != "" and row.column[DateTo] != "") {
			let txt = callMacro("ex_PostProcessActions.m_TextAppend", txt, "Термін: {row.column[DaysCount]} (з {row.column[DateFrom]} по {row.column[DateTo]}).", "\n");
		}

		if (row.column[RaportFrom] != "" and row.column[InNum] != "" and row.column[InDate] != "") {
			let txt = callMacro("ex_PostProcessActions.m_TextAppend", txt, "Підстава: рапорт {row.column[RaportFrom]} (вх. №{row.column[InNum]} від {row.column[InDate]}).", "\n");
		}

		if (row.column[DocNum] != "" and row.column[DocDate] != "") {
			let txt = callMacro("ex_PostProcessActions.m_TextAppend", txt, "Виписка з медичної карти №{row.column[DocNum]} від {row.column[DocDate]}.", "\n");
		}

		if (row.column[VkNum] != "" and row.column[VkDate] != "") {
			let txt = callMacro("ex_PostProcessActions.m_TextAppend", txt, "В/к №{row.column[VkNum]} від {row.column[VkDate]}.", "\n");
		}

		if (row.column[VlkNum] != "" and row.column[VlkDate] != "") {
			let txt = callMacro("ex_PostProcessActions.m_TextAppend", txt, "ВЛК №{row.column[VlkNum]} від {row.column[VlkDate]}.", "\n");
		}

		callMacro("ex_PostProcessActions.m_SetRowCellText", row, "DocNote", txt);
	}

	/* Продолжение блока: строка без Hospital дописывается в блок выше */
	if (row.column[Hospital] == "" and row.column[FIO] != "" and row.column[Rank] != "" and row.column[Position] != "") {
		callMacro("ex_PostProcessActions.m_AppendToOwnerRowCell", row, "Hospital", "DocNote", "{row.column[Rank]} {row.column[FIO]}, {row.column[Position]}.", "\n");
	}

	if (row.column[Hospital] == "" and row.column[Vacation] != "") {
		callMacro("ex_PostProcessActions.m_AppendToOwnerRowCell", row, "Hospital", "DocNote", "Статус: {row.column[Vacation]}.", "\n");
	}

	if (row.column[Hospital] == "" and row.column[DaysCount] != "" and row.column[DateFrom] != "" and row.column[DateTo] != "") {
		callMacro("ex_PostProcessActions.m_AppendToOwnerRowCell", row, "Hospital", "DocNote", "Термін: {row.column[DaysCount]} (з {row.column[DateFrom]} по {row.column[DateTo]}).", "\n");
	}

	if (row.column[Hospital] == "" and row.column[RaportFrom] != "" and row.column[InNum] != "" and row.column[InDate] != "") {
		callMacro("ex_PostProcessActions.m_AppendToOwnerRowCell", row, "Hospital", "DocNote", "Підстава: рапорт {row.column[RaportFrom]} (вх. №{row.column[InNum]} від {row.column[InDate]}).", "\n");
	}

	if (row.column[Hospital] == "" and row.column[DocNum] != "" and row.column[DocDate] != "") {
		callMacro("ex_PostProcessActions.m_AppendToOwnerRowCell", row, "Hospital", "DocNote", "Виписка з медичної карти №{row.column[DocNum]} від {row.column[DocDate]}.", "\n");
	}

	if (row.column[Hospital] == "" and row.column[VkNum] != "" and row.column[VkDate] != "") {
		callMacro("ex_PostProcessActions.m_AppendToOwnerRowCell", row, "Hospital", "DocNote", "В/к №{row.column[VkNum]} від {row.column[VkDate]}.", "\n");
	}

	if (row.column[Hospital] == "" and row.column[VlkNum] != "" and row.column[VlkDate] != "") {
		callMacro("ex_PostProcessActions.m_AppendToOwnerRowCell", row, "Hospital", "DocNote", "ВЛК №{row.column[VlkNum]} від {row.column[VlkDate]}.", "\n");
	}

	if (row.column[DocNote] != "") {
		callMacro("ex_PostProcessActions.m_HighlightRowCell", row, "DocNote", "#404040");
		callMacro("ex_PostProcessActions.m_EmphasizeRowCellTextByRegex", row, "DocNote", "№\\s*[0-9]+", "#FF0000", "false");
	}
}

if (Events.Sheet[DailyEvents].count != "0") {
	callMacro("ex_PostProcessActions.m_AppendPostProcessFooterText", "DailyEvents rows: {Events.Sheet[DailyEvents].count}");
}
